/// Compile-time CRC-32 lookup table (reflected polynomial 0xEDB88320).
const CRC32_TABLE: [u32; 256] = {
    let mut table = [0u32; 256];
    let mut n = 0usize;
    while n < 256 {
        let mut c = n as u32;
        let mut k = 0;
        while k < 8 {
            c = if c & 1 != 0 { 0xEDB8_8320 ^ (c >> 1) } else { c >> 1 };
            k += 1;
        }
        table[n] = c;
        n += 1;
    }
    table
};

/// Compute the RFC 1952 / IEEE 802.3 CRC-32 checksum.
/// `seed` is the previous checksum (use 0 to start fresh).
pub fn crc32(seed: u32, buf: &[u8]) -> u32 {
    let mut c = seed ^ 0xFFFF_FFFF;
    for &b in buf {
        c = CRC32_TABLE[((c ^ b as u32) & 0xFF) as usize] ^ (c >> 8);
    }
    c ^ 0xFFFF_FFFF
}

const CRC32_MSB_POLY: u32 = 0x04C1_1DB7;

pub fn crc32_msb(seed: u32, buf: &[u8]) -> u32 {
    let mut c = seed ^ 0xFFFF_FFFF;
    for &b in buf {
        c ^= (b as u32) << 24;
        for _ in 0..8 {
            c = if c & 0x8000_0000 != 0 { (c << 1) ^ CRC32_MSB_POLY } else { c << 1 };
        }
    }
    c ^ 0xFFFF_FFFF
}
